import React from 'react';
import { Event } from '../types';

interface EventsCardProps {
	events: Event[];
	loading?: boolean;
	error?: string | null;
}

const EventsCard: React.FC<EventsCardProps> = ({ events, loading, error }) => {
	console.log('EventsCard props:', { events, loading, error, eventsLength: events?.length });

	if (loading) {
		return (
			<div className="bg-white rounded-lg shadow-lg p-8">
				<div className="flex items-center justify-center py-8">
					<div className="animate-spin rounded-full h-8 w-8 border-b-2 border-uncc-green mr-3"></div>
					<span className="text-gray-600">Loading events...</span>
				</div>
			</div>
		);
	}

	if (error) {
		return (
			<div className="bg-white rounded-lg shadow-lg p-8">
				<div className="bg-red-100 border-l-4 border-red-500 text-red-700 p-4 rounded">
					{error}
				</div>
			</div>
		);
	}

	return (
		<div className="bg-white rounded-lg shadow-lg p-8">
			<h2 className="text-2xl font-bold text-uncc-green mb-6">Upcoming Events in Charlotte</h2>
			<div className="space-y-2">
				{events.map((event) => (
					<div key={event.id} className="flex justify-between items-center py-2 border-b border-gray-100 last:border-b-0">
						<span className="font-medium text-gray-800">{event.name}</span>
						<span className="text-sm text-gray-600">{event.date}</span>
					</div>
				))}
			</div>
		</div>
	);
};

export default EventsCard;
